import { useNavigate } from "react-router-dom";
import "./styles/Home.css";
import { useEffect } from "react";

function Home() {
  const navigate = useNavigate();
useEffect(() => {
  const section = document.querySelector(".about-section");

  const onScroll = () => {
    if (section.getBoundingClientRect().top < window.innerHeight - 150) {
      section.classList.add("visible");
    }
  };

  window.addEventListener("scroll", onScroll);
  return () => window.removeEventListener("scroll", onScroll);
}, []);

  return (
    <div className="home-page">
      <div className="home-hero">
        <div className="hero-text">
          <h1>
            Where <br />
            stories <br />
            <span>sleep in shelves.</span>
          </h1>

          <p>
            Welcome to a quiet corner of magic. A digital sanctuary where
            books are preserved, discovered, and cared for.
          </p>

          <button
            className="enter-btn"
            onClick={() => navigate("/auth")}
          >
            ENTER THE ARCHIVES
          </button>
        </div>

        <div className="hero-images">
          <img
            src="https://images.unsplash.com/photo-1524995997946-a1c2e315a42f"
            alt="Library shelves"
            className="hero-img"
          />

          <img
            src="https://images.unsplash.com/photo-1507842217343-583bb7270b66"
            alt="Library corridor"
            className="hero-img offset"
          />
        </div>
      </div>
{/* ABOUT SECTION */}
<section className="about-section">
  <h2>About the Archive</h2>
  <p>
    BookSphere is not just a library system.  
    It is a living archive where stories are preserved,
    borrowed, and remembered.
  </p>

  <p>
    Designed for students, librarians, and keepers of knowledge,
    this space brings order to imagination and structure to stories.
  </p>
</section>

      <div className="home-footer">
        <span>BookSphere • Est. MMXXVI</span>
      </div>
    </div>
  );
}

export default Home;
